// Classic class component pattern (still valid, but not recommended for new code)
class Counter extends React.Component {
  constructor(props) {
    super(props);
    this.state = { count: 0 };
    this.handleClick = this.handleClick.bind(this); // manual binding required
  }

  componentDidMount() {
    document.title = `Count: ${this.state.count}`;
  }

  componentDidUpdate(prevProps, prevState) {
    if (prevState.count !== this.state.count) {
      document.title = `Count: ${this.state.count}`;
    }
  }

  handleClick() {
    this.setState(prev => ({ count: prev.count + 1 }));
  }

  render() {
    return (
      <button onClick={this.handleClick}>
        Count: {this.state.count}
      </button>
    );
  }
}

// The same Counter, rewritten with hooks (React 16.8+)
function Counter() {
  const [count, setCount] = useState(0);

  useEffect(() => {
    document.title = `Count: ${count}`;
  }, [count]); // runs when count changes

  return (
    <button onClick={() => setCount(c => c + 1)}>
      Count: {count}
    </button>
  );
}

// Custom hook — reusable stateful logic
function useDocumentTitle(title) {
  useEffect(() => {
    document.title = title;
    return () => { document.title = 'My App'; }; // cleanup
  }, [title]);
}

// Usage in any component:
function Counter() {
  const [count, setCount] = useState(0);
  useDocumentTitle(`Count: ${count}`);
  return <button onClick={() => setCount(c => c + 1)}>Count: {count}</button>;
}

// React 17 and earlier — synchronous rendering
ReactDOM.render(<App />, document.getElementById('root'));

// React 18 — concurrent rendering enabled
const root = ReactDOM.createRoot(document.getElementById('root'));
root.render(<App />);

// useTransition: keep typing fast while a slow list updates in background
function SearchPage() {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState([]);
  const [isPending, startTransition] = useTransition();

  function handleChange(e) {
    setQuery(e.target.value); // urgent: update the input immediately
    startTransition(() => {
      setResults(searchHeavyList(e.target.value)); // non-urgent: can be interrupted
    });
  }

  return (
    <>
      <input value={query} onChange={handleChange} />
      {isPending ? <Spinner /> : <ResultsList items={results} />}
    </>
  );
}

// Server Component — runs on the server, never sent to the client
// No useState, no useEffect — those only exist client-side
async function UserProfile({ userId }) {
  // Direct database access — safe because this code never runs in the browser
  const user = await db.users.findById(userId);
  return (
    <section>
      <h1>{user.name}</h1>
      <p>{user.bio}</p>
      {/* Client Component for interactive parts */}
      <FollowButton userId={userId} initialFollowing={user.isFollowing} />
    </section>
  );
}

'use client'; // everything below runs in the browser

function FollowButton({ userId, initialFollowing }) {
  const [following, setFollowing] = useState(initialFollowing);

  async function handleClick() {
    const next = !following;
    setFollowing(next);  // optimistic update
    await toggleFollow(userId, next);
  }

  return (
    <button onClick={handleClick}>
      {following ? 'Unfollow' : 'Follow'}
    </button>
  );
}

// Old: componentDidMount + componentWillUnmount for subscriptions
class OldChat extends React.Component {
  componentDidMount() {
    this.subscription = chatAPI.subscribe(this.props.roomId, this.handleMessage);
  }
  componentWillUnmount() {
    this.subscription.unsubscribe();
  }
  handleMessage = (msg) => this.setState({ messages: [...this.state.messages, msg] });
}

// New: useEffect with cleanup function
function NewChat({ roomId }) {
  const [messages, setMessages] = useState([]);
  useEffect(() => {
    const sub = chatAPI.subscribe(roomId, msg =>
      setMessages(prev => [...prev, msg])
    );
    return () => sub.unsubscribe();  // cleanup on unmount or roomId change
  }, [roomId]);
}

