// In development: your components render twice, effects run twice.
// This is intentional — if a bug only appears on the second render,
// you have an impure component or a missing cleanup.

// Modern React test with React Testing Library
import { render, screen, userEvent } from '@testing-library/react';
import Counter from './Counter';

test('increments count on click', async () => {
  render(<Counter />);
  expect(screen.getByText('Count: 0')).toBeInTheDocument();
  await userEvent.click(screen.getByRole('button'));
  expect(screen.getByText('Count: 1')).toBeInTheDocument();
});
// No knowledge of useState, no access to component internals.
// Tests what the user sees and does.

// useDeferredValue: lower-priority version of query for heavy list
function HeavySearch({ allItems }) {
  const [query, setQuery] = useState('');
  const deferredQuery = useDeferredValue(query); // lags behind query when busy
  const isStale = query !== deferredQuery;

  const filtered = useMemo(
    () => allItems.filter(i => i.name.includes(deferredQuery)),
    [allItems, deferredQuery]
  );

  return (
    <>
      <input value={query} onChange={e => setQuery(e.target.value)} />
      <div style={{ opacity: isStale ? 0.6 : 1 }}>
        {filtered.map(i => <Item key={i.id} item={i} />)}
      </div>
    </>
  );
}
